class Solution:
    def sortString(self, s: str) -> str:
        s = list(s)
        result = []
        while s:
            smallest = min(s)
            result.append(smallest)
            s.remove(smallest)
            largest = max(s)
            result.append(largest)
            s.remove(largest)
        return ''.join(result)
